import { useState, useEffect, useRef } from "react";

// ── Config ────────────────────────────────────────────────────────────────────
const PRICE_KEY = "dcl_prices";
const DEFAULT_PRICES = {
  "Wash & Fold": 15.00,
  "Dry Cleaning": 25.00,
  "Ironing Only": 10.00,
  "Duvet/Large": 35.00,
};

const ROLES = [
  { key: "client", label: "Client",  color: "#00c6e0", desc: "Enter your invoice number to track your order" },
  { key: "staff",  label: "Staff",   color: "#10b981", desc: "Manage laundry operations" },
  { key: "owner",  label: "Owner",   color: "#f59e0b", desc: "Full access & analytics" },
];

const DEMO_USERS = {
  staff: { email: "staff@deepcitadel.com", password: "staff123" },
  owner: { email: "owner@deepcitadel.com", password: "owner123" },
};

const VALID_INVOICES = ["INV-DEMO001", "INV-001", "INV-002", "INV-003"];

const SERVICE_META = {
  "Wash & Fold":  { icon: "Wash",  accent: "#00c6e0" },
  "Dry Cleaning": { icon: "Steam", accent: "#10b981" },
  "Ironing Only": { icon: "Iron",  accent: "#f59e0b" },
  "Duvet/Large":  { icon: "Duvet", accent: "#818cf8" },
};

// ── Shared Styles ─────────────────────────────────────────────────────────────
const CSS = `
  @import url('https://fonts.googleapis.com/css2?family=Cinzel:wght@700&family=Syne:wght@600;700;800&family=DM+Sans:wght@300;400;500;600&display=swap');
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
  body { background: #020e1a; font-family: 'DM Sans', sans-serif; }

  @keyframes logoGlow {
    0%,100% { box-shadow: 0 0 20px rgba(0,198,224,0.3), 0 0 40px rgba(0,119,182,0.2); }
    50%      { box-shadow: 0 0 35px rgba(0,198,224,0.7), 0 0 70px rgba(0,119,182,0.4); }
  }
  @keyframes spin    { to { transform: rotate(360deg); } }
  @keyframes shake   { 0%,100%{transform:translateX(0);} 20%,60%{transform:translateX(-7px);} 40%,80%{transform:translateX(7px);} }
  @keyframes slideUp { from{opacity:0;transform:translateY(18px);} to{opacity:1;transform:translateY(0);} }
  @keyframes floatUp { 0%{transform:translateY(0) scale(1);opacity:0.1;} 50%{opacity:0.15;} 100%{transform:translateY(-100vh) scale(0.5);opacity:0;} }
  @keyframes sIn     { from{opacity:0;transform:translateX(-5px);} to{opacity:1;transform:translateX(0);} }
  @keyframes fadeIn  { from{opacity:0;} to{opacity:1;} }

  input::placeholder { color: rgba(255,255,255,0.25); }
  input:focus { outline: none; }
  input::-webkit-outer-spin-button, input::-webkit-inner-spin-button { -webkit-appearance: none; }
`;

// ── Animated Canvas Background (shared across all views) ─────────────────────
function DeepCitadelBackground() {
  const canvasRef = useRef(null);
  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext("2d");
    let animId, W, H;
    const bubbles = [];
    const BUBBLE_COUNT = 28;
    function resize() { W = canvas.width = canvas.offsetWidth; H = canvas.height = canvas.offsetHeight; }
    function initBubbles() {
      bubbles.length = 0;
      for (let i = 0; i < BUBBLE_COUNT; i++) {
        bubbles.push({ x: Math.random()*W, y: H+Math.random()*H, r: 8+Math.random()*38,
          speed: 0.3+Math.random()*0.7, drift: (Math.random()-0.5)*0.4,
          opacity: 0.04+Math.random()*0.10, phase: Math.random()*Math.PI*2 });
      }
    }
    resize(); initBubbles();
    window.addEventListener("resize", ()=>{ resize(); initBubbles(); });
    let t = 0;
    function draw() {
      t += 0.008; ctx.clearRect(0,0,W,H);
      const bg = ctx.createLinearGradient(0,0,W*0.6,H);
      bg.addColorStop(0,"#020e1a"); bg.addColorStop(0.4,"#021824");
      bg.addColorStop(0.75,"#031e30"); bg.addColorStop(1,"#041525");
      ctx.fillStyle=bg; ctx.fillRect(0,0,W,H);
      const g1=ctx.createRadialGradient(W*.15,H*.2,0,W*.15,H*.2,W*.45);
      g1.addColorStop(0,"rgba(0,168,204,0.13)"); g1.addColorStop(1,"rgba(0,168,204,0)");
      ctx.fillStyle=g1; ctx.fillRect(0,0,W,H);
      const g2=ctx.createRadialGradient(W*.85,H*.8,0,W*.85,H*.8,W*.4);
      g2.addColorStop(0,"rgba(16,185,129,0.10)"); g2.addColorStop(1,"rgba(16,185,129,0)");
      ctx.fillStyle=g2; ctx.fillRect(0,0,W,H);
      for (let w=0;w<5;w++) {
        ctx.beginPath(); ctx.strokeStyle=`rgba(0,180,220,${0.025+w*0.008})`; ctx.lineWidth=1.2;
        const yB=H*(0.2+w*0.16);
        for (let x=0;x<=W;x+=4) { const y=yB+Math.sin((x/W)*Math.PI*3+t+w*1.1)*(18+w*6); x===0?ctx.moveTo(x,y):ctx.lineTo(x,y); }
        ctx.stroke();
      }
      bubbles.forEach(b=>{
        b.y-=b.speed; b.x+=Math.sin(t*0.8+b.phase)*b.drift;
        if(b.y+b.r<0){b.y=H+b.r;b.x=Math.random()*W;}
        ctx.beginPath();
        const gr=ctx.createRadialGradient(b.x-b.r*.3,b.y-b.r*.3,b.r*.1,b.x,b.y,b.r);
        gr.addColorStop(0,`rgba(180,240,255,${b.opacity*1.5})`);
        gr.addColorStop(0.5,`rgba(0,180,220,${b.opacity})`);
        gr.addColorStop(1,`rgba(0,100,160,0)`);
        ctx.arc(b.x,b.y,b.r,0,Math.PI*2); ctx.fillStyle=gr; ctx.fill();
        ctx.beginPath(); ctx.arc(b.x,b.y,b.r,0,Math.PI*2);
        ctx.strokeStyle=`rgba(180,240,255,${b.opacity*0.8})`; ctx.lineWidth=0.6; ctx.stroke();
      });
      ctx.strokeStyle="rgba(0,180,220,0.022)"; ctx.lineWidth=0.5;
      for(let x=0;x<W;x+=60){ctx.beginPath();ctx.moveTo(x,0);ctx.lineTo(x,H);ctx.stroke();}
      for(let y=0;y<H;y+=60){ctx.beginPath();ctx.moveTo(0,y);ctx.lineTo(W,y);ctx.stroke();}
      animId=requestAnimationFrame(draw);
    }
    draw();
    return ()=>{ cancelAnimationFrame(animId); window.removeEventListener("resize",resize); };
  },[]);
  return <canvas ref={canvasRef} style={{position:"fixed",inset:0,width:"100%",height:"100%",zIndex:0,display:"block"}}/>;
}

// ── Floating Particles (login only) ──────────────────────────────────────────
function Particles() {
  const dots = Array.from({length:14},(_,i)=>({
    id:i, size:Math.random()*4+2, left:Math.random()*100,
    delay:Math.random()*8, dur:Math.random()*10+8, opacity:Math.random()*0.12+0.04
  }));
  return <>{dots.map(d=>(
    <div key={d.id} style={{position:"fixed",borderRadius:"50%",width:d.size,height:d.size,
      left:`${d.left}%`,bottom:"-10px",background:`rgba(0,198,224,${d.opacity})`,
      animation:`floatUp ${d.dur}s ${d.delay}s infinite linear`,pointerEvents:"none",zIndex:0}}/>
  ))}</>;
}

// ── Shared Logo ───────────────────────────────────────────────────────────────
function DCLogo({ size = "md" }) {
  const big = size === "lg";
  return (
    <div style={{textAlign:"center", marginBottom: big ? 28 : 0}}>
      <div style={{
        width: big?80:42, height: big?80:42, borderRadius: big?"50%":"12px",
        margin: big?"0 auto 16px":0,
        background:"linear-gradient(135deg,#0077b6,#00c6e0)",
        display:"flex", alignItems:"center", justifyContent:"center",
        animation: big?"logoGlow 3s ease-in-out infinite":"none",
        boxShadow: big?"0 0 0 0 rgba(0,198,224,0.4)":"0 0 20px rgba(0,198,224,0.4)",
        position:"relative", flexShrink:0,
      }}>
        {big && <div style={{position:"absolute",inset:-4,borderRadius:"50%",border:"2px solid transparent",
          borderTopColor:"#00c6e0",borderRightColor:"rgba(0,198,224,0.3)",animation:"spin 3s linear infinite"}}/>}
        <span style={{fontFamily:"'Cinzel',serif",color:"#fff",fontSize:big?26:15,fontWeight:700,letterSpacing:-1}}>DC</span>
      </div>
      {big && <>
        <h1 style={{fontFamily:"'Cinzel',serif",color:"#fff",fontSize:22,letterSpacing:1,margin:"0 0 4px"}}>Deep Citadel</h1>
        <p style={{color:"rgba(255,255,255,0.35)",fontSize:12,letterSpacing:2,textTransform:"uppercase"}}>Laundry Services</p>
      </>}
    </div>
  );
}

// ── SVG Icons ─────────────────────────────────────────────────────────────────
const Icon = {
  Eye:     ()=><svg width="15" height="15" fill="currentColor" viewBox="0 0 16 16"><path d="M16 8s-3-5.5-8-5.5S0 8 0 8s3 5.5 8 5.5S16 8 16 8zM1.173 8a13.133 13.133 0 0 1 1.66-2.043C4.12 4.668 5.88 3.5 8 3.5c2.12 0 3.879 1.168 5.168 2.457A13.133 13.133 0 0 1 14.828 8c-.058.087-.122.183-.195.288-.335.48-.83 1.12-1.465 1.755C11.879 11.332 10.119 12.5 8 12.5c-2.12 0-3.879-1.168-5.168-2.457A13.134 13.134 0 0 1 1.172 8z"/><path d="M8 5.5a2.5 2.5 0 1 0 0 5 2.5 2.5 0 0 0 0-5zM4.5 8a3.5 3.5 0 1 1 7 0 3.5 3.5 0 0 1-7 0z"/></svg>,
  EyeOff:  ()=><svg width="15" height="15" fill="currentColor" viewBox="0 0 16 16"><path d="M13.359 11.238C15.06 9.72 16 8 16 8s-3-5.5-8-5.5a7.028 7.028 0 0 0-2.79.588l.77.771A5.944 5.944 0 0 1 8 3.5c2.12 0 3.879 1.168 5.168 2.457A13.134 13.134 0 0 1 14.828 8c-.058.087-.122.183-.195.288-.335.48-.83 1.12-1.465 1.755-.165.165-.337.328-.517.486l.708.709z"/><path d="M11.297 9.176a3.5 3.5 0 0 0-4.474-4.474l.823.823a2.5 2.5 0 0 1 2.829 2.829l.822.822zm-2.943 1.299.822.822a3.5 3.5 0 0 1-4.474-4.474l.823.823a2.5 2.5 0 0 0 2.829 2.829z"/><path d="M3.35 5.47c-.18.16-.353.322-.518.487A13.134 13.134 0 0 0 1.172 8l.195.288c.335.48.83 1.12 1.465 1.755C4.121 11.332 5.881 12.5 8 12.5c.716 0 1.39-.133 2.02-.36l.77.772A7.029 7.029 0 0 1 8 13.5C3 13.5 0 8 0 8s.939-1.721 2.641-3.238l.708.709zm10.296 8.884-12-12 .708-.708 12 12-.708.708z"/></svg>,
  Mail:    ()=><svg width="14" height="14" fill="currentColor" viewBox="0 0 16 16"><path d="M0 4a2 2 0 0 1 2-2h12a2 2 0 0 1 2 2v8a2 2 0 0 1-2 2H2a2 2 0 0 1-2-2V4Zm2-1a1 1 0 0 0-1 1v.217l7 4.2 7-4.2V4a1 1 0 0 0-1-1H2Zm13 2.383-4.708 2.825L15 11.105V5.383Zm-.034 6.876-5.64-3.471L8 9.583l-1.326-.795-5.64 3.47A1 1 0 0 0 2 13h12a1 1 0 0 0 .966-.741ZM1 11.105l4.708-2.897L1 5.383v5.722Z"/></svg>,
  Lock:    ()=><svg width="14" height="14" fill="currentColor" viewBox="0 0 16 16"><path d="M8 1a2 2 0 0 1 2 2v4H6V3a2 2 0 0 1 2-2zm3 6V3a3 3 0 0 0-6 0v4a2 2 0 0 0-2 2v5a2 2 0 0 0 2 2h6a2 2 0 0 0 2-2V9a2 2 0 0 0-2-2z"/></svg>,
  Invoice: ()=><svg width="14" height="14" fill="currentColor" viewBox="0 0 16 16"><path d="M14.5 3a.5.5 0 0 1 .5.5v9a.5.5 0 0 1-.5.5h-13a.5.5 0 0 1-.5-.5v-9a.5.5 0 0 1 .5-.5h13zm-13-1A1.5 1.5 0 0 0 0 3.5v9A1.5 1.5 0 0 0 1.5 14h13a1.5 1.5 0 0 0 1.5-1.5v-9A1.5 1.5 0 0 0 14.5 2h-13z"/><path d="M3 5.5a.5.5 0 0 1 .5-.5h9a.5.5 0 0 1 0 1h-9a.5.5 0 0 1-.5-.5zM3 8a.5.5 0 0 1 .5-.5h9a.5.5 0 0 1 0 1h-9A.5.5 0 0 1 3 8zm0 2.5a.5.5 0 0 1 .5-.5h6a.5.5 0 0 1 0 1h-6a.5.5 0 0 1-.5-.5z"/></svg>,
  Check:   ()=><svg width="10" height="10" fill="currentColor" viewBox="0 0 16 16"><path d="M13.854 3.646a.5.5 0 0 1 0 .708l-7 7a.5.5 0 0 1-.708 0l-3.5-3.5a.5.5 0 1 1 .708-.708L6.5 10.293l6.646-6.647a.5.5 0 0 1 .708 0z"/></svg>,
  Alert:   ()=><svg width="12" height="12" fill="currentColor" viewBox="0 0 16 16"><path d="M8.982 1.566a1.13 1.13 0 0 0-1.96 0L.165 13.233c-.457.778.091 1.767.98 1.767h13.713c.889 0 1.438-.99.98-1.767L8.982 1.566zM8 5c.535 0 .954.462.9.995l-.35 3.507a.552.552 0 0 1-1.1 0L7.1 5.995A.905.905 0 0 1 8 5zm.002 6a1 1 0 1 1 0 2 1 1 0 0 1 0-2z"/></svg>,
  ArrowLeft: ()=><svg width="11" height="11" fill="currentColor" viewBox="0 0 16 16"><path fillRule="evenodd" d="M15 8a.5.5 0 0 0-.5-.5H2.707l3.147-3.146a.5.5 0 1 0-.708-.708l-4 4a.5.5 0 0 0 0 .708l4 4a.5.5 0 0 0 .708-.708L2.707 8.5H14.5A.5.5 0 0 0 15 8z"/></svg>,
  Minus:   ()=><svg width="11" height="11" fill="currentColor" viewBox="0 0 16 16"><path d="M2 8a1 1 0 0 1 1-1h10a1 1 0 1 1 0 2H3a1 1 0 0 1-1-1z"/></svg>,
  Plus:    ()=><svg width="11" height="11" fill="currentColor" viewBox="0 0 16 16"><path d="M8 2a1 1 0 0 1 1 1v4h4a1 1 0 0 1 0 2H9v4a1 1 0 0 1-2 0V9H3a1 1 0 0 1 0-2h4V3a1 1 0 0 1 1-1z"/></svg>,
  Trash:   ()=><svg width="11" height="11" fill="currentColor" viewBox="0 0 16 16"><path d="M5.5 5.5A.5.5 0 0 1 6 6v6a.5.5 0 0 1-1 0V6a.5.5 0 0 1 .5-.5zm2.5 0a.5.5 0 0 1 .5.5v6a.5.5 0 0 1-1 0V6a.5.5 0 0 1 .5-.5zm3 .5a.5.5 0 0 0-1 0v6a.5.5 0 0 0 1 0V6z"/><path fillRule="evenodd" d="M14.5 3a1 1 0 0 1-1 1H13v9a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V4h-.5a1 1 0 0 1-1-1V2a1 1 0 0 1 1-1H6a1 1 0 0 1 1-1h2a1 1 0 0 1 1 1h3.5a1 1 0 0 1 1 1v1zM4.118 4 4 4.059V13a1 1 0 0 0 1 1h6a1 1 0 0 0 1-1V4.059L11.882 4H4.118zM2.5 3V2h11v1h-11z"/></svg>,
  Print:   ()=><svg width="13" height="13" fill="currentColor" viewBox="0 0 16 16"><path d="M2.5 8a.5.5 0 1 0 0-1 .5.5 0 0 0 0 1z"/><path d="M5 1a2 2 0 0 0-2 2v2H2a2 2 0 0 0-2 2v3a2 2 0 0 0 2 2h1v1a2 2 0 0 0 2 2h6a2 2 0 0 0 2-2v-1h1a2 2 0 0 0 2-2V7a2 2 0 0 0-2-2h-1V3a2 2 0 0 0-2-2H5zM4 3a1 1 0 0 1 1-1h6a1 1 0 0 1 1 1v2H4V3zm1 5a2 2 0 0 0-2 2v1H2a1 1 0 0 1-1-1V7a1 1 0 0 1 1-1h12a1 1 0 0 1 1 1v3a1 1 0 0 1-1 1h-1v-1a2 2 0 0 0-2-2H5zm7 2v3a1 1 0 0 1-1 1H5a1 1 0 0 1-1-1v-3a1 1 0 0 1 1-1h6a1 1 0 0 1 1 1z"/></svg>,
  Cart:    ()=><svg width="13" height="13" fill="currentColor" viewBox="0 0 16 16"><path d="M0 1.5A.5.5 0 0 1 .5 1H2a.5.5 0 0 1 .485.379L2.89 3H14.5a.5.5 0 0 1 .491.592l-1.5 8A.5.5 0 0 1 13 12H4a.5.5 0 0 1-.491-.408L2.01 3.607 1.61 2H.5a.5.5 0 0 1-.5-.5zM3.102 4l1.313 7h8.17l1.313-7H3.102zM5 12a2 2 0 1 0 0 4 2 2 0 0 0 0-4zm7 0a2 2 0 1 0 0 4 2 2 0 0 0 0-4zm-7 1a1 1 0 1 1 0 2 1 1 0 0 1 0-2zm7 0a1 1 0 1 1 0 2 1 1 0 0 1 0-2z"/></svg>,
  User:    ()=><svg width="13" height="13" fill="currentColor" viewBox="0 0 16 16"><path d="M8 8a3 3 0 1 0 0-6 3 3 0 0 0 0 6zm2-3a2 2 0 1 1-4 0 2 2 0 0 1 4 0zm4 8c0 1-1 1-1 1H3s-1 0-1-1 1-4 6-4 6 3 6 4zm-1-.004c-.001-.246-.154-.986-.832-1.664C11.516 10.68 10.029 10 8 10c-2.03 0-3.516.68-4.168 1.332-.678.678-.83 1.418-.832 1.664h10z"/></svg>,
  Phone:   ()=><svg width="13" height="13" fill="currentColor" viewBox="0 0 16 16"><path fillRule="evenodd" d="M1.885.511a1.745 1.745 0 0 1 2.61.163L6.29 2.98c.329.423.445.974.315 1.494l-.547 2.19a.678.678 0 0 0 .178.643l2.457 2.457a.678.678 0 0 0 .644.178l2.189-.547a1.745 1.745 0 0 1 1.494.315l2.306 1.794c.829.645.905 1.87.163 2.611l-1.034 1.034c-.74.74-1.846 1.065-2.877.702a18.634 18.634 0 0 1-7.01-4.42 18.634 18.634 0 0 1-4.42-7.009c-.362-1.03-.037-2.137.703-2.877L1.885.511z"/></svg>,
  Wash:    ()=><svg width="20" height="20" fill="none" stroke="currentColor" strokeWidth="1.5" viewBox="0 0 24 24"><circle cx="12" cy="12" r="9"/><circle cx="12" cy="12" r="4"/><path d="M9 9c1-1 3-1 4 0"/></svg>,
  Steam:   ()=><svg width="20" height="20" fill="none" stroke="currentColor" strokeWidth="1.5" viewBox="0 0 24 24"><path d="M3 17l3-6 3 6 3-6 3 6 3-6"/></svg>,
  Iron:    ()=><svg width="20" height="20" fill="none" stroke="currentColor" strokeWidth="1.5" viewBox="0 0 24 24"><path d="M4 17h12l4-8H8L4 17z"/><circle cx="7" cy="20" r="1.5"/><circle cx="14" cy="20" r="1.5"/></svg>,
  Duvet:   ()=><svg width="20" height="20" fill="none" stroke="currentColor" strokeWidth="1.5" viewBox="0 0 24 24"><rect x="2" y="6" width="20" height="14" rx="3"/><path d="M2 10h20M8 10v10M16 10v10"/></svg>,
  SignOut: ()=><svg width="13" height="13" fill="currentColor" viewBox="0 0 16 16"><path fillRule="evenodd" d="M10 12.5a.5.5 0 0 1-.5.5h-8a.5.5 0 0 1-.5-.5v-9a.5.5 0 0 1 .5-.5h8a.5.5 0 0 1 .5.5v2a.5.5 0 0 0 1 0v-2A1.5 1.5 0 0 0 9.5 2h-8A1.5 1.5 0 0 0 0 3.5v9A1.5 1.5 0 0 0 1.5 14h8a1.5 1.5 0 0 0 1.5-1.5v-2a.5.5 0 0 0-1 0v2z"/><path fillRule="evenodd" d="M15.854 8.354a.5.5 0 0 0 0-.708l-3-3a.5.5 0 0 0-.708.708L14.293 7.5H5.5a.5.5 0 0 0 0 1h8.793l-2.147 2.146a.5.5 0 0 0 .708.708l3-3z"/></svg>,
};

// ── Reusable Login Input ──────────────────────────────────────────────────────
function LoginInput({ icon, type, placeholder, value, onChange, error, right }) {
  return (
    <div style={{marginBottom: error ? 6 : 16}}>
      <div style={{position:"relative",display:"flex",alignItems:"center"}}>
        <span style={{position:"absolute",left:14,color:error?"#ef4444":"rgba(255,255,255,0.3)",zIndex:1,display:"flex"}}>{icon}</span>
        <input type={type} placeholder={placeholder} value={value} onChange={onChange}
          style={{width:"100%",padding:"12px 14px 12px 42px",paddingRight:right?42:14,borderRadius:12,
            border:`1.5px solid ${error?"#ef4444":value?"#00c6e0":"rgba(255,255,255,0.12)"}`,
            background:"rgba(255,255,255,0.06)",color:"#fff",fontSize:14,
            fontFamily:"'DM Sans',sans-serif",transition:"border-color 0.2s,box-shadow 0.2s",
            boxShadow:error?"0 0 0 3px rgba(239,68,68,0.1)":value?"0 0 0 3px rgba(0,198,224,0.08)":"none"}}/>
        {right && <span style={{position:"absolute",right:14,zIndex:1}}>{right}</span>}
      </div>
      {error && <p style={{color:"#fca5a5",fontSize:11,display:"flex",alignItems:"center",gap:4,marginTop:5}}><Icon.Alert/> {error}</p>}
    </div>
  );
}

// ── Submit Button ─────────────────────────────────────────────────────────────
function SubmitBtn({ loading, label, onClick, type="button", color="#0077b6" }) {
  return (
    <button type={type} onClick={onClick} disabled={loading}
      style={{width:"100%",padding:"14px",borderRadius:12,
        background:`linear-gradient(135deg,${color},#00c6e0)`,
        color:"#fff",border:"none",fontWeight:700,fontSize:15,
        fontFamily:"'DM Sans',sans-serif",
        boxShadow:"0 4px 20px rgba(0,119,182,0.4)",
        transition:"all 0.3s",cursor:loading?"not-allowed":"pointer",opacity:loading?0.8:1}}>
      {loading
        ? <span style={{display:"flex",alignItems:"center",gap:8,justifyContent:"center"}}>
            <span style={{width:16,height:16,border:"2px solid rgba(255,255,255,0.3)",borderTopColor:"#fff",borderRadius:"50%",display:"inline-block",animation:"spin 0.7s linear infinite"}}/>
            Please wait…
          </span>
        : label}
    </button>
  );
}

// ── Forgot Password ───────────────────────────────────────────────────────────
function ForgotPassword({ onBack }) {
  const [step,    setStep]    = useState(1);
  const [email,   setEmail]   = useState("");
  const [otp,     setOtp]     = useState(["","","","","",""]);
  const [loading, setLoading] = useState(false);
  const [error,   setError]   = useState("");

  const sendOTP = () => {
    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) { setError("Enter a valid email."); return; }
    setLoading(true); setError("");
    setTimeout(()=>{ setLoading(false); setStep(2); }, 1200);
  };
  const verifyOTP = () => {
    if (otp.join("").length < 6) { setError("Enter the full 6-digit code."); return; }
    setLoading(true); setError("");
    setTimeout(()=>{ setLoading(false); setStep(3); }, 1000);
  };
  const handleOtpChange = (i, val) => {
    if (!/^\d?$/.test(val)) return;
    const next=[...otp]; next[i]=val; setOtp(next);
    if (val && i < 5) document.getElementById(`otp-${i+1}`)?.focus();
  };

  return (
    <div style={{animation:"slideUp 0.4s ease"}}>
      <button onClick={onBack} style={{background:"transparent",border:"none",color:"rgba(255,255,255,0.5)",cursor:"pointer",display:"flex",alignItems:"center",gap:6,fontSize:13,marginBottom:20,fontFamily:"'DM Sans',sans-serif"}}>
        <Icon.ArrowLeft/> Back to Login
      </button>
      {step === 1 && <>
        <h2 style={{fontFamily:"'Cinzel',serif",color:"#fff",fontSize:20,marginBottom:8}}>Forgot Password?</h2>
        <p style={{color:"rgba(255,255,255,0.45)",fontSize:13,marginBottom:24,lineHeight:1.6}}>Enter your email and we'll send a reset code.</p>
        <LoginInput icon={<Icon.Mail/>} type="email" placeholder="Your email address" value={email} error={error}
          onChange={e=>{ setEmail(e.target.value); setError(""); }}/>
        <SubmitBtn loading={loading} label="Send Reset Code" onClick={sendOTP}/>
      </>}
      {step === 2 && <>
        <h2 style={{fontFamily:"'Cinzel',serif",color:"#fff",fontSize:20,marginBottom:8}}>Check Your Email</h2>
        <p style={{color:"rgba(255,255,255,0.45)",fontSize:13,marginBottom:24,lineHeight:1.6}}>We sent a 6-digit code to <span style={{color:"#00c6e0"}}>{email}</span></p>
        <div style={{display:"flex",gap:8,justifyContent:"center",marginBottom:20}}>
          {otp.map((v,i)=>(
            <input key={i} id={`otp-${i}`} type="text" maxLength={1} value={v}
              onChange={e=>handleOtpChange(i,e.target.value)}
              onKeyDown={e=>{ if(e.key==="Backspace"&&!v&&i>0) document.getElementById(`otp-${i-1}`)?.focus(); }}
              style={{width:44,height:52,borderRadius:12,border:`2px solid ${v?"#00c6e0":"rgba(255,255,255,0.15)"}`,
                background:"rgba(255,255,255,0.06)",color:"#fff",fontSize:22,textAlign:"center",
                fontFamily:"'Cinzel',serif",outline:"none",transition:"border-color 0.2s"}}/>
          ))}
        </div>
        {error && <p style={{color:"#fca5a5",fontSize:11,display:"flex",alignItems:"center",gap:4,marginBottom:12}}><Icon.Alert/> {error}</p>}
        <SubmitBtn loading={loading} label="Verify Code" onClick={verifyOTP}/>
      </>}
      {step === 3 && (
        <div style={{textAlign:"center",animation:"slideUp 0.4s ease"}}>
          <div style={{width:64,height:64,borderRadius:"50%",background:"rgba(16,185,129,0.15)",border:"2px solid #10b981",display:"flex",alignItems:"center",justifyContent:"center",margin:"0 auto 16px"}}>
            <span style={{color:"#10b981",fontSize:28}}>✓</span>
          </div>
          <h3 style={{fontFamily:"'Cinzel',serif",color:"#fff",fontSize:18,marginBottom:8}}>Code Verified!</h3>
          <p style={{color:"rgba(255,255,255,0.45)",fontSize:13,marginBottom:24}}>For demo purposes, your reset is complete!</p>
          <button onClick={onBack} style={{width:"100%",padding:"14px",borderRadius:12,background:"linear-gradient(135deg,#0077b6,#00c6e0)",color:"#fff",border:"none",fontWeight:700,fontSize:15,fontFamily:"'DM Sans',sans-serif",cursor:"pointer"}}>Back to Login</button>
        </div>
      )}
    </div>
  );
}

// ══════════════════════════════════════════════════════════════════════════════
// LOGIN VIEW
// ══════════════════════════════════════════════════════════════════════════════
function LoginView({ onLogin }) {
  const [role,       setRole]       = useState("client");
  const [email,      setEmail]      = useState("");
  const [password,   setPassword]   = useState("");
  const [invoiceNum, setInvoiceNum] = useState("");
  const [showPwd,    setShowPwd]    = useState(false);
  const [remember,   setRemember]   = useState(false);
  const [loading,    setLoading]    = useState(false);
  const [errors,     setErrors]     = useState({});
  const [shake,      setShake]      = useState(false);
  const [forgot,     setForgot]     = useState(false);
  const [loaded,     setLoaded]     = useState(false);

  useEffect(()=>{ setTimeout(()=>setLoaded(true),100); },[]);

  const activeRole = ROLES.find(r=>r.key===role);

  const validate = () => {
    const e = {};
    if (role === "client") {
      if (!invoiceNum.trim()) e.invoiceNum = "Invoice number is required.";
      else if (!invoiceNum.trim().toUpperCase().startsWith("INV-")) e.invoiceNum = "Must start with INV- (e.g. INV-001).";
    } else {
      if (!email.trim()) e.email = "Email is required.";
      else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) e.email = "Enter a valid email.";
      if (!password.trim()) e.password = "Password is required.";
      else if (password.length < 6) e.password = "At least 6 characters required.";
    }
    return e;
  };

  const handleLogin = (e) => {
    e?.preventDefault();
    const errs = validate();
    if (Object.keys(errs).length) {
      setErrors(errs); setShake(true); setTimeout(()=>setShake(false),500); return;
    }
    setErrors({}); setLoading(true);
    setTimeout(()=>{
      if (role === "client") {
        const valid = VALID_INVOICES.includes(invoiceNum.trim().toUpperCase());
        if (valid) { onLogin(role); }
        else { setLoading(false); setErrors({general:"Invoice not found. Try a demo number below."}); setShake(true); setTimeout(()=>setShake(false),500); }
      } else {
        const demo = DEMO_USERS[role];
        const ok = email===demo.email && password===demo.password;
        if (ok) { onLogin(role); }
        else { setLoading(false); setErrors({general:`Invalid credentials. Use demo credentials below.`}); setShake(true); setTimeout(()=>setShake(false),500); }
      }
    }, 1200);
  };

  return (
    <div style={{minHeight:"100vh",display:"flex",alignItems:"center",justifyContent:"center",padding:16,position:"relative",overflow:"hidden"}}>
      <Particles/>
      <div style={{width:"100%",maxWidth:420,position:"relative",zIndex:1,
        opacity:loaded?1:0,transform:loaded?"translateY(0)":"translateY(24px)",
        transition:"all 0.7s cubic-bezier(0.22,1,0.36,1)"}}>

        <DCLogo size="lg"/>

        <div style={{background:"rgba(5,20,40,0.65)",backdropFilter:"blur(24px)",borderRadius:24,
          padding:"32px 28px",border:"1px solid rgba(0,198,224,0.12)",
          boxShadow:"0 20px 60px rgba(0,0,0,0.5)",
          animation:shake?"shake 0.5s ease":"none"}}>

          {forgot ? <ForgotPassword onBack={()=>setForgot(false)}/> : (
            <>
              {/* Role selector */}
              <div style={{marginBottom:24}}>
                <p style={{color:"rgba(255,255,255,0.4)",fontSize:11,letterSpacing:1.5,textTransform:"uppercase",marginBottom:10}}>Sign in as</p>
                <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:8}}>
                  {ROLES.map(r=>(
                    <button key={r.key} onClick={()=>{ setRole(r.key); setErrors({}); }}
                      style={{padding:"11px 8px",borderRadius:12,border:`2px solid ${role===r.key?r.color:"rgba(255,255,255,0.08)"}`,
                        background:role===r.key?`${r.color}18`:"transparent",
                        color:role===r.key?r.color:"rgba(255,255,255,0.4)",
                        fontFamily:"'DM Sans',sans-serif",fontSize:12,fontWeight:600,
                        cursor:"pointer",transition:"all 0.25s",
                        display:"flex",flexDirection:"column",alignItems:"center",gap:5}}>
                      <span style={{fontSize:18}}>{r.key==="client"?"👤":r.key==="staff"?"👔":"🛡️"}</span>
                      {r.label}
                    </button>
                  ))}
                </div>
                <p style={{color:"rgba(255,255,255,0.25)",fontSize:11,marginTop:8,textAlign:"center"}}>{activeRole?.desc}</p>
              </div>

              <form onSubmit={handleLogin}>
                {errors.general && (
                  <div style={{padding:"11px 14px",borderRadius:10,background:"rgba(239,68,68,0.1)",border:"1px solid rgba(239,68,68,0.25)",marginBottom:16,display:"flex",alignItems:"flex-start",gap:8}}>
                    <span style={{color:"#ef4444",flexShrink:0,marginTop:1}}><Icon.Alert/></span>
                    <p style={{color:"#fca5a5",fontSize:12,lineHeight:1.5}}>{errors.general}</p>
                  </div>
                )}

                {role === "client" ? (
                  <>
                    <LoginInput icon={<Icon.Invoice/>} type="text" placeholder="Invoice number (e.g. INV-001)"
                      value={invoiceNum} error={errors.invoiceNum}
                      onChange={e=>{ setInvoiceNum(e.target.value.toUpperCase()); setErrors(p=>({...p,invoiceNum:"",general:""})); }}/>
                    <div style={{padding:"11px 14px",borderRadius:10,background:"rgba(0,198,224,0.05)",border:"1px solid rgba(0,198,224,0.12)",marginBottom:16}}>
                      <p style={{color:"rgba(255,255,255,0.4)",fontSize:12,lineHeight:1.6}}>
                        📄 Your invoice number is on your receipt, e.g. <span style={{color:"#00c6e0",fontWeight:600}}>INV-001</span>. Contact us on WhatsApp if needed.
                      </p>
                    </div>
                  </>
                ) : (
                  <>
                    <LoginInput icon={<Icon.Mail/>} type="email" placeholder="Email address"
                      value={email} error={errors.email}
                      onChange={e=>{ setEmail(e.target.value); setErrors(p=>({...p,email:"",general:""})); }}/>
                    <LoginInput icon={<Icon.Lock/>} type={showPwd?"text":"password"} placeholder="Password"
                      value={password} error={errors.password}
                      onChange={e=>{ setPassword(e.target.value); setErrors(p=>({...p,password:"",general:""})); }}
                      right={<button type="button" onClick={()=>setShowPwd(s=>!s)}
                        style={{background:"transparent",border:"none",cursor:"pointer",color:"rgba(255,255,255,0.35)",display:"flex",alignItems:"center",padding:0}}>
                        {showPwd?<Icon.EyeOff/>:<Icon.Eye/>}
                      </button>}/>
                  </>
                )}

                {role !== "client" && (
                  <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20}}>
                    <label style={{display:"flex",alignItems:"center",gap:8,cursor:"pointer"}} onClick={()=>setRemember(r=>!r)}>
                      <div style={{width:18,height:18,borderRadius:5,border:`2px solid ${remember?"#00c6e0":"rgba(255,255,255,0.2)"}`,
                        background:remember?"#00c6e0":"transparent",display:"flex",alignItems:"center",justifyContent:"center",transition:"all 0.2s",flexShrink:0}}>
                        {remember && <Icon.Check/>}
                      </div>
                      <span style={{color:"rgba(255,255,255,0.45)",fontSize:13}}>Remember me</span>
                    </label>
                    <button type="button" onClick={()=>{ setForgot(true); setErrors({}); }}
                      style={{background:"transparent",border:"none",color:"#00c6e0",fontSize:13,cursor:"pointer",fontFamily:"'DM Sans',sans-serif",fontWeight:600}}>
                      Forgot password?
                    </button>
                  </div>
                )}

                <SubmitBtn loading={loading} label="Sign In" type="submit"/>
              </form>

              {/* Demo hints */}
              <div style={{marginTop:18,padding:"13px 16px",borderRadius:12,background:"rgba(0,198,224,0.05)",border:"1px solid rgba(0,198,224,0.10)"}}>
                {role === "client" ? <>
                  <p style={{color:"rgba(255,255,255,0.35)",fontSize:11,letterSpacing:1,textTransform:"uppercase",marginBottom:8}}>Demo Invoice Numbers</p>
                  <div style={{display:"flex",flexWrap:"wrap",gap:6}}>
                    {VALID_INVOICES.map(inv=>(
                      <span key={inv} onClick={()=>setInvoiceNum(inv)}
                        style={{padding:"3px 10px",borderRadius:20,background:"rgba(0,198,224,0.1)",border:"1px solid rgba(0,198,224,0.2)",
                          color:"#00c6e0",fontSize:11,fontWeight:600,cursor:"pointer",fontFamily:"monospace"}}>
                        {inv}
                      </span>
                    ))}
                  </div>
                  <p style={{color:"rgba(255,255,255,0.2)",fontSize:10,marginTop:6}}>Click any to auto-fill</p>
                </> : <>
                  <p style={{color:"rgba(255,255,255,0.35)",fontSize:11,letterSpacing:1,textTransform:"uppercase",marginBottom:8}}>Demo Credentials</p>
                  {ROLES.filter(r=>r.key!=="client").map(r=>(
                    <div key={r.key} style={{display:"flex",justifyContent:"space-between",marginBottom:4}}>
                      <span style={{color:r.color,fontSize:11,fontWeight:700}}>{r.label}</span>
                      <span style={{color:"rgba(255,255,255,0.3)",fontSize:11,fontFamily:"monospace"}}>
                        {DEMO_USERS[r.key].email.split("@")[0]} / {DEMO_USERS[r.key].password}
                      </span>
                    </div>
                  ))}
                </>}
              </div>
            </>
          )}
        </div>

        <p style={{textAlign:"center",color:"rgba(255,255,255,0.2)",fontSize:12,marginTop:20}}>
          © {new Date().getFullYear()} <span style={{color:"rgba(255,255,255,0.35)",fontFamily:"'Cinzel',serif"}}>Deep Citadel</span> · Powerful Clean. Trusted Care.
        </p>
      </div>
    </div>
  );
}

// ══════════════════════════════════════════════════════════════════════════════
// POS VIEW
// ══════════════════════════════════════════════════════════════════════════════
function POSView({ role, onLogout }) {
  const [activePrices] = useState(()=>{
    try { const s=localStorage.getItem(PRICE_KEY); return s?JSON.parse(s):DEFAULT_PRICES; }
    catch { return DEFAULT_PRICES; }
  });

  const services = Object.keys(activePrices);
  const [quantities, setQuantities] = useState(()=>Object.fromEntries(services.map(k=>[k,0])));
  const [cart,       setCart]       = useState([]);
  const [customer,   setCustomer]   = useState({name:"",phone:""});

  const totalAmount = cart.reduce((s,i)=>s+i.subtotal,0);
  const totalItems  = cart.reduce((s,i)=>s+i.qty,0);
  const hasQty      = Object.values(quantities).some(q=>q>0);

  const roleColor = ROLES.find(r=>r.key===role)?.color || "#00c6e0";

  const setQty = (service, val) => {
    const n = Math.max(0,Math.min(99,isNaN(parseInt(val))?0:parseInt(val)));
    setQuantities(prev=>({...prev,[service]:n}));
  };

  const buildOrder = () => {
    const items = Object.entries(quantities)
      .filter(([,qty])=>qty>0)
      .map(([name,qty])=>({
        id:`${name}-${Date.now()}`, name, qty,
        unitPrice: activePrices[name]||0,
        subtotal: qty*(activePrices[name]||0),
      }));
    setCart(items);
  };

  const removeFromCart = (id) => {
    const item=cart.find(i=>i.id===id);
    if(item) setQty(item.name,0);
    setCart(prev=>prev.filter(i=>i.id!==id));
  };

  const clearAll = () => {
    setCart([]);
    setQuantities(Object.fromEntries(services.map(k=>[k,0])));
  };

  return (
    <div style={{position:"relative",zIndex:1,minHeight:"100vh",fontFamily:"'DM Sans',sans-serif",padding:"22px 28px",color:"#e8f4f8"}}>

      {/* Header */}
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:24}}>
        <div style={{display:"flex",alignItems:"center",gap:12}}>
          <DCLogo size="sm"/>
          <div style={{marginLeft:4}}>
            <div style={{fontFamily:"'Cinzel',serif",fontWeight:700,fontSize:20,color:"#fff",letterSpacing:0.5}}>Deep Citadel</div>
            <div style={{fontSize:11,color:"rgba(255,255,255,0.35)",letterSpacing:2,textTransform:"uppercase"}}>Point of Sale</div>
          </div>
        </div>
        <div style={{display:"flex",alignItems:"center",gap:12}}>
          <div style={{background:`${roleColor}18`,border:`1px solid ${roleColor}44`,color:roleColor,fontSize:11,fontWeight:600,letterSpacing:1.5,padding:"5px 14px",borderRadius:20,textTransform:"uppercase"}}>
            ● {role}
          </div>
          <button onClick={onLogout}
            style={{display:"flex",alignItems:"center",gap:7,background:"rgba(255,255,255,0.05)",border:"1px solid rgba(255,255,255,0.1)",
              color:"rgba(255,255,255,0.5)",borderRadius:10,padding:"7px 14px",cursor:"pointer",fontSize:12,
              fontFamily:"'DM Sans',sans-serif",transition:"all 0.2s"}}
            onMouseEnter={e=>{e.currentTarget.style.color="#fff";e.currentTarget.style.borderColor="rgba(255,255,255,0.25)";}}
            onMouseLeave={e=>{e.currentTarget.style.color="rgba(255,255,255,0.5)";e.currentTarget.style.borderColor="rgba(255,255,255,0.1)";}}>
            <Icon.SignOut/> Sign Out
          </button>
        </div>
      </div>

      {/* Grid */}
      <div style={{display:"grid",gridTemplateColumns:"1.3fr 1fr",gap:22}}>

        {/* LEFT — Service quantity form */}
        <div style={{background:"rgba(5,25,45,0.62)",border:"1px solid rgba(0,198,224,0.12)",borderRadius:20,backdropFilter:"blur(20px)",padding:24,boxShadow:"0 8px 40px rgba(0,0,0,0.4),inset 0 1px 0 rgba(255,255,255,0.05)"}}>
          <div style={{fontFamily:"'Syne',sans-serif",fontWeight:700,fontSize:15,color:"#fff",letterSpacing:-0.3}}>Select Services</div>
          <div style={{fontSize:11,color:"rgba(255,255,255,0.3)",margin:"3px 0 20px",letterSpacing:0.5}}>Enter quantity per service, then add to order</div>

          <div style={{display:"flex",flexDirection:"column",gap:10}}>
            {services.map(service=>{
              const meta  = SERVICE_META[service]||{icon:"Wash",accent:"#00c6e0"};
              const SvcIcon = Icon[meta.icon]||Icon.Wash;
              const qty   = quantities[service]||0;
              const sub   = qty*(activePrices[service]||0);
              return (
                <div key={service} style={{
                  display:"flex",alignItems:"center",gap:14,
                  background: qty>0?"rgba(255,255,255,0.055)":"rgba(255,255,255,0.03)",
                  border:`1px solid ${qty>0?meta.accent+"44":"rgba(255,255,255,0.07)"}`,
                  borderRadius:14,padding:"13px 16px",
                  borderLeft:`${qty>0?"3px":"1px"} solid ${qty>0?meta.accent:"rgba(255,255,255,0.07)"}`,
                  transition:"all 0.2s",
                }}>
                  <div style={{width:40,height:40,borderRadius:11,flexShrink:0,display:"flex",alignItems:"center",justifyContent:"center",background:"rgba(255,255,255,0.05)",border:"1px solid rgba(255,255,255,0.08)",color:meta.accent}}>
                    <SvcIcon/>
                  </div>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{fontFamily:"'Syne',sans-serif",fontWeight:600,fontSize:13.5,color:"#e8f4f8"}}>{service}</div>
                    <div style={{fontSize:12,color:meta.accent,marginTop:2}}>${(activePrices[service]||0).toFixed(2)} per item</div>
                    {qty>0 && <div style={{fontSize:11,color:"rgba(255,255,255,0.38)",marginTop:2}}>→ ${sub.toFixed(2)}</div>}
                  </div>
                  <div style={{display:"flex",alignItems:"center",background:"rgba(0,0,0,0.3)",border:"1px solid rgba(255,255,255,0.1)",borderRadius:10,overflow:"hidden",flexShrink:0}}>
                    <button onClick={()=>setQty(service,qty-1)}
                      style={{width:32,height:36,border:"none",background:"transparent",color:"rgba(255,255,255,0.45)",cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",transition:"all 0.15s"}}
                      onMouseEnter={e=>e.currentTarget.style.background="rgba(255,255,255,0.08)"}
                      onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
                      <Icon.Minus/>
                    </button>
                    <input type="number" min="0" max="99"
                      value={qty===0?"":qty} placeholder="0"
                      onChange={e=>setQty(service,e.target.value)}
                      style={{width:44,height:36,background:"transparent",border:"none",borderLeft:"1px solid rgba(255,255,255,0.08)",borderRight:"1px solid rgba(255,255,255,0.08)",color:"#fff",textAlign:"center",fontFamily:"'Syne',sans-serif",fontWeight:700,fontSize:14,outline:"none"}}/>
                    <button onClick={()=>setQty(service,qty+1)}
                      style={{width:32,height:36,border:"none",background:"transparent",color:"rgba(255,255,255,0.45)",cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",transition:"all 0.15s"}}
                      onMouseEnter={e=>{e.currentTarget.style.background="rgba(0,198,224,0.2)";e.currentTarget.style.color="#00c6e0";}}
                      onMouseLeave={e=>{e.currentTarget.style.background="transparent";e.currentTarget.style.color="rgba(255,255,255,0.45)";}}>
                      <Icon.Plus/>
                    </button>
                  </div>
                </div>
              );
            })}
          </div>

          <button onClick={buildOrder} disabled={!hasQty}
            style={{width:"100%",marginTop:18,padding:13,borderRadius:12,border:"none",
              background:hasQty?"linear-gradient(135deg,#0077b6,#00c6e0)":"rgba(255,255,255,0.05)",
              color:hasQty?"#fff":"rgba(255,255,255,0.2)",fontFamily:"'Syne',sans-serif",fontWeight:700,
              fontSize:13.5,cursor:hasQty?"pointer":"not-allowed",display:"flex",alignItems:"center",justifyContent:"center",gap:8,
              transition:"all 0.2s",boxShadow:hasQty?"0 4px 18px rgba(0,198,224,0.28)":"none"}}>
            <Icon.Cart/> Add to Order
          </button>
        </div>

        {/* RIGHT — Order Summary */}
        <div style={{background:"rgba(5,25,45,0.62)",border:"1px solid rgba(0,198,224,0.12)",borderRadius:20,backdropFilter:"blur(20px)",padding:24,boxShadow:"0 8px 40px rgba(0,0,0,0.4),inset 0 1px 0 rgba(255,255,255,0.05)"}}>
          <div style={{display:"flex",alignItems:"center",marginBottom:3}}>
            <div style={{fontFamily:"'Syne',sans-serif",fontWeight:700,fontSize:15,color:"#fff"}}>Order Summary</div>
            {cart.length>0 && <span style={{background:"rgba(0,198,224,0.15)",border:"1px solid rgba(0,198,224,0.25)",color:"#00c6e0",borderRadius:6,padding:"2px 8px",fontSize:11,fontWeight:600,marginLeft:8}}>{totalItems} item{totalItems!==1?"s":""}</span>}
          </div>
          <div style={{fontSize:11,color:"rgba(255,255,255,0.3)",margin:"3px 0 16px"}}>Customer details &amp; order breakdown</div>

          {/* Customer inputs */}
          {["name","phone"].map(field=>(
            <div key={field} style={{display:"flex",alignItems:"center",gap:10,background:"rgba(0,0,0,0.25)",border:"1px solid rgba(255,255,255,0.07)",borderRadius:10,padding:"11px 14px",marginBottom:8,transition:"border-color 0.2s"}}
              onFocus={e=>e.currentTarget.style.borderColor="rgba(0,198,224,0.35)"}
              onBlur={e=>e.currentTarget.style.borderColor="rgba(255,255,255,0.07)"}>
              <span style={{color:"rgba(0,198,224,0.6)",flexShrink:0}}>{field==="name"?<Icon.User/>:<Icon.Phone/>}</span>
              <input className="bare-input" placeholder={field==="name"?"Customer Name":"Phone Number"}
                value={customer[field]} onChange={e=>setCustomer({...customer,[field]:e.target.value})}
                style={{background:"transparent",border:"none",outline:"none",color:"#e8f4f8",fontFamily:"'DM Sans',sans-serif",fontSize:13.5,width:"100%"}}/>
            </div>
          ))}

          <div style={{borderTop:"1px solid rgba(255,255,255,0.07)",margin:"14px 0"}}/>

          {/* Cart */}
          <div style={{minHeight:160}}>
            {cart.length===0 ? (
              <div style={{textAlign:"center",color:"rgba(255,255,255,0.18)",fontSize:13,padding:"38px 0",lineHeight:1.7}}>Set quantities on the left<br/>then tap Add to Order</div>
            ) : (
              cart.map(item=>(
                <div key={item.id} style={{display:"grid",gridTemplateColumns:"1fr auto auto",alignItems:"center",gap:10,padding:"9px 0",borderBottom:"1px solid rgba(255,255,255,0.05)",animation:"sIn 0.2s ease"}}>
                  <div>
                    <div style={{color:"rgba(255,255,255,0.8)",fontSize:13}}>{item.name}</div>
                    <div style={{fontSize:11,color:"rgba(255,255,255,0.32)",marginTop:2}}>{item.qty} × ${item.unitPrice.toFixed(2)}</div>
                  </div>
                  <div style={{color:"#00c6e0",fontWeight:700,fontFamily:"'Syne',sans-serif",fontSize:13}}>${item.subtotal.toFixed(2)}</div>
                  <button onClick={()=>removeFromCart(item.id)}
                    style={{background:"rgba(239,68,68,0.1)",border:"1px solid rgba(239,68,68,0.2)",color:"#ef4444",borderRadius:6,width:26,height:26,display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer",transition:"all 0.15s"}}
                    onMouseEnter={e=>e.currentTarget.style.background="rgba(239,68,68,0.25)"}
                    onMouseLeave={e=>e.currentTarget.style.background="rgba(239,68,68,0.1)"}>
                    <Icon.Trash/>
                  </button>
                </div>
              ))
            )}
          </div>

          {/* Total */}
          <div style={{marginTop:16,paddingTop:16,borderTop:"1px dashed rgba(0,198,224,0.2)"}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"baseline",marginBottom:14}}>
              <span style={{fontSize:12,color:"rgba(255,255,255,0.4)",textTransform:"uppercase",letterSpacing:1.5}}>Total Due</span>
              <span style={{fontFamily:"'Syne',sans-serif",fontWeight:800,fontSize:26,color:"#00c6e0",textShadow:"0 0 20px rgba(0,198,224,0.5)"}}>${totalAmount.toFixed(2)}</span>
            </div>
            <div style={{display:"flex",gap:10}}>
              <button onClick={clearAll} disabled={cart.length===0}
                style={{padding:"13px 16px",borderRadius:12,border:"1px solid rgba(255,255,255,0.1)",background:"rgba(255,255,255,0.04)",color:cart.length===0?"rgba(255,255,255,0.2)":"rgba(255,255,255,0.5)",fontFamily:"'Syne',sans-serif",fontWeight:600,fontSize:13,cursor:cart.length===0?"not-allowed":"pointer",transition:"all 0.2s",flexShrink:0}}
                onMouseEnter={e=>{ if(cart.length>0){e.currentTarget.style.color="#fff";e.currentTarget.style.background="rgba(255,255,255,0.08)";} }}
                onMouseLeave={e=>{ e.currentTarget.style.color=cart.length===0?"rgba(255,255,255,0.2)":"rgba(255,255,255,0.5)";e.currentTarget.style.background="rgba(255,255,255,0.04)"; }}>
                Clear
              </button>
              <button disabled={cart.length===0}
                style={{flex:1,padding:13,borderRadius:12,border:"none",
                  background:cart.length>0?"linear-gradient(135deg,#10b981,#059669)":"rgba(255,255,255,0.05)",
                  color:cart.length>0?"#fff":"rgba(255,255,255,0.2)",fontFamily:"'Syne',sans-serif",fontWeight:700,fontSize:13.5,
                  cursor:cart.length>0?"pointer":"not-allowed",display:"flex",alignItems:"center",justifyContent:"center",gap:8,
                  transition:"all 0.2s",boxShadow:cart.length>0?"0 4px 18px rgba(16,185,129,0.3)":"none"}}>
                <Icon.Print/> Process &amp; Print
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

// ══════════════════════════════════════════════════════════════════════════════
// ROOT APP
// ══════════════════════════════════════════════════════════════════════════════
export default function DeepCitadelApp() {
  const [session, setSession] = useState(null); // null = logged out

  const handleLogin  = (role) => setSession(role);
  const handleLogout = ()     => setSession(null);

  return (
    <>
      <style>{CSS}</style>
      <DeepCitadelBackground/>
      {session
        ? <POSView role={session} onLogout={handleLogout}/>
        : <LoginView onLogin={handleLogin}/>
      }
    </>
  );
}
